using System.ComponentModel.DataAnnotations;

namespace sv_71aa8e78c2b34471a300ad285615c052.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

using sv_71aa8e78c2b34471a300ad285615c052.Models;

namespace sv_71aa8e78c2b34471a300ad285615c052.Services;

public class ReviewService
{
    /// <summary>
    /// Validates the review against server-side business rules and submits it if valid.
    /// Returns a dictionary of field-specific errors (field name -> error message).
    /// An empty dictionary means the submission succeeded.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(ReviewModel review, List<PhotoInfo>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // Additional server-side rules can be added here.

        // If no errors, the review is considered submitted successfully.
        return Task.FromResult(errors);
    }
}

public class PhotoInfo
{
    public string FileName { get; set; } = string.Empty;
    public long Size { get; set; }
    public byte[] Content { get; set; } = [];
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_71aa8e78c2b34471a300ad285615c052.Models
@using sv_71aa8e78c2b34471a300ad285615c052.Services
@inject ReviewService ReviewService

<h3>Write a Review</h3>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your review has been submitted successfully.
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="review-form">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Product Name</label>
            <InputText class="form-control" @bind-Value="model.ProductName" />
            <ValidationMessage For="() => model.ProductName" />
            @if (serverErrors.ContainsKey(nameof(model.ProductName)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Rating (1–5)</label>
            <InputNumber class="form-control" @bind-Value="model.Rating" />
            <ValidationMessage For="() => model.Rating" />
            @if (serverErrors.ContainsKey(nameof(model.Rating)))
            {
                <div class="text-danger">@serverErrors[nameof(model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Review Title</label>
            <InputText class="form-control" @bind-Value="model.ReviewTitle" />
            <ValidationMessage For="() => model.ReviewTitle" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewTitle)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Review Body</label>
            <InputTextArea class="form-control" rows="5" @bind-Value="model.ReviewBody" />
            <ValidationMessage For="() => model.ReviewBody" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewBody)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile class="form-control" multiple OnChange="OnFilesSelected" accept=".jpg,.jpeg,.png" />
            @if (!string.IsNullOrEmpty(photoError))
            {
                <div class="text-danger">@photoError</div>
            }
            @if (selectedPhotos.Count > 0)
            {
                <ul class="list-group mt-2">
                    @foreach (var photo in selectedPhotos)
                    {
                        <li class="list-group-item d-flex justify-content-between align-items-center">
                            @photo.FileName
                            <span class="badge bg-secondary">@FormatSize(photo.Size)</span>
                        </li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Submit Review")
        </button>
    </EditForm>
}

@code {
    private ReviewModel model = new();
    private List<PhotoInfo> selectedPhotos = new();
    private Dictionary<string, string> serverErrors = new();
    private string? photoError;
    private bool submitted;
    private bool isSubmitting;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFiles = 3;
    private static readonly string[] AllowedExtensions = [".jpg", ".jpeg", ".png"];

    private async Task OnFilesSelected(InputFileChangeEventArgs e)
    {
        photoError = null;
        selectedPhotos.Clear();

        if (e.FileCount > MaxFiles)
        {
            photoError = $"You can upload a maximum of {MaxFiles} photos.";
            return;
        }

        foreach (var file in e.GetMultipleFiles(MaxFiles))
        {
            var extension = Path.GetExtension(file.Name).ToLowerInvariant();
            if (!AllowedExtensions.Contains(extension))
            {
                photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
                selectedPhotos.Clear();
                return;
            }

            if (file.Size > MaxFileSize)
            {
                photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
                selectedPhotos.Clear();
                return;
            }

            using var stream = file.OpenReadStream(maxAllowedSize: MaxFileSize);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);

            selectedPhotos.Add(new PhotoInfo
            {
                FileName = file.Name,
                Size = file.Size,
                Content = ms.ToArray()
            });
        }
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(model, selectedPhotos);

            if (errors.Count > 0)
            {
                serverErrors = errors;
            }
            else
            {
                submitted = true;
            }
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

